Base.metadata.create_all(bind=engine)

# GraphQL Types
@strawberry.type
class ReviewType:
    id: int
    product_id: int
    author: str
    content: str
    rating: int
    created_at: datetime

@strawberry.type
class SellerType:
    id: int
    product_id: int
    name: str
    email: str
    phone: str

@strawberry.type
class CategoryType:
    id: int
    name: str

@strawberry.type
class ImageType:
    id: int
    product_id: int
    url: str
    alt_text: str

@strawberry.type
class ProductType:
    id: int
    name: str
    description: str
    price: float
    created_at: datetime
    reviews: list[ReviewType]
    sellers: list[SellerType]
    categories: list[CategoryType]
    images: list[ImageType]

# Resolvers
def get_db():
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()

@strawberry.type
class Query:
    @strawberry.field
    def product(self, info, id: int) -> ProductType:
        db = next(get_db())
        return db.query(Product).filter(Product.id == id).first()
    
    @strawberry.field
    def products(self, info) -> list[ProductType]:
        db = next(get_db())
        return db.query(Product).all()
    
    @strawberry.field
    def category(self, info, id: int) -> CategoryType:
        db = next(get_db())
        return db.query(Category).filter(Category.id == id).first()
    
    @strawberry.field
    def categories(self, info) -> list[CategoryType]:
        db = next(get_db())
        return db.query(Category).all()

# Create GraphQL schema
schema = strawberry.Schema(query=Query)

# FastAPI app
app = FastAPI()
graphql_app = GraphQLRouter(schema=schema, graphiql=True)
app.include_router(graphql_app, prefix="/graphql")

# Security middleware
from fastapi.middleware.cors import CORSMiddleware
from fastapi.middleware.trustedhost import TrustedHostMiddleware

app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)

app.add_middleware(
    TrustedHostMiddleware,
    allowed_hosts=["*"]
)